// === src/pages/Shop.js ===
import React, { useEffect, useState } from 'react';
import './Shop.css';

const handleDelete = (productToDelete) => {
  const all = JSON.parse(localStorage.getItem('products')) || [];
  const updated = all.filter(p => p.name !== productToDelete.name);
  localStorage.setItem('products', JSON.stringify(updated));
  window.location.reload();
};

const handleEdit = (productToEdit) => {
  alert(`This would open an editable form for: ${productToEdit.name}`);
};

const handleAddToCart = (product) => {
  const cart = JSON.parse(localStorage.getItem('cart')) || [];
  cart.push(product);
  localStorage.setItem('cart', JSON.stringify(cart));
  alert(`${product.name} added to cart!`);
};

const defaultSections = {
  Plants: [
    { name: 'Areca Palm', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/areca_palm.jpg', price: 399 },
    { name: 'ZZ Plant', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/zz_plant.jpg', price: 349 },
  ],
  Flowers: [
    { name: 'Peace Lily', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/peace_lily.jpg', price: 299 },
    { name: 'Anthurium Red', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/anthurium_red.jpg', price: 399 },
  ],
  Seeds: [
    { name: 'Tomato Seeds', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/tomato-seeds.jpg', price: 49 },
    { name: 'Coriander Seeds', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/coriander-seeds.jpg', price: 39 },
  ],
  Pots: [
    { name: 'Ceramic Pot Blue', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/ceramic-pot.jpg', price: 199 },
    { name: 'Terracotta Planter', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/terracotta.jpg', price: 149 },
  ],
  Decor: [
    { name: 'Miniature Fencing', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/fence_decor.jpg', price: 79 },
    { name: 'Wooden Tray', image: 'https://cdn.shopify.com/s/files/1/0059/8835/2052/products/wood_tray.jpg', price: 129 },
  ],
};

const Shop = () => {
  const [shopData, setShopData] = useState(defaultSections);

  useEffect(() => {
    const added = JSON.parse(localStorage.getItem('products')) || [];
    const updatedSections = { ...defaultSections };

    added.forEach((item) => {
      const cat = item.category || 'Plants';
      if (!updatedSections[cat]) updatedSections[cat] = [];
      updatedSections[cat].push(item);
    });

    setShopData(updatedSections);
  }, []);

  return (
    <div className="shop-container">
      <h2 className="shop-title">Shop All Categories</h2>
      {Object.entries(shopData).map(([category, items], idx) => (
        <div key={idx} className="shop-section">
          <h3>{category}</h3>
          <div className="shop-grid">
            {items.map((item, i) => (
              <div className="product-card" key={i}>
                <img src={item.image} alt={item.name} />
                <h4>{item.name}</h4>
                <p>₹{item.price}</p>

                <div className="admin-actions">
                  <button onClick={() => handleEdit(item)}>Edit</button>
                  <button onClick={() => handleDelete(item)}>Delete</button>
                </div>
                <button className="cart-btn" onClick={() => handleAddToCart(item)}>Add to Cart</button>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default Shop;
